import React , { useState ,useEffect } from 'react';
import './styles.scss';
import { Link } from 'react-router-dom'

import img1 from '../../assets/images/background/bg-ft.png'
import img2 from '../../assets/images/background/bg-ft2.png'
import {BsTwitter, BsWhatsapp, BsGithub} from 'react-icons/bs'
import {AiOutlineMail} from 'react-icons/ai'

function Footer(props) {

    const [isVisible, setIsVisible] = useState(false);

    const scrollToTop = () => {
      window.scrollTo({
        top: 0,
        behavior: "smooth"
      });
    };
  
    useEffect(() => {
      const toggleVisibility = () => {
        if (window.pageYOffset > 500) {
          setIsVisible(true);
        } else {
          setIsVisible(false);
        }
      };
  
      window.addEventListener("scroll", toggleVisibility);
  
      return () => window.removeEventListener("scroll", toggleVisibility);
    }, []);

    return (
        <footer id="footer">
            <div className="footer-main">
                <img src={img1} alt="" className="bg1" />
                <img src={img2} alt="" className="bg2" />
                <div className="container">
                    <ul className="widget-social">
                        <li>
                            <a href="https://github.com/HaiderJavaid" target={'_blank'}>
                            <BsGithub style={{color: 'white', fontSize: '25px'}}/>
                            </a>
                        </li>
                        <li>
                        <a href="https://twitter.com/muhd_haider/" target={'_blank'}>
                           <BsTwitter style={{color: 'white', fontSize: '25px'}}/>
                        </a>
                        </li>
                        <li>
                            
                            <a href="https://wa.link/tt8mh4" target='_blank'>
                            <BsWhatsapp style={{color: 'white', fontSize: '25px'}}/>                        
                            </a>
                        </li>
                        <li>
                            
                            <a href="#">
                            <AiOutlineMail style={{color: 'white', fontSize: '25px'}}/>                        
                            
                            </a>
                        </li>
                    </ul>
                    <h5 className="heading">Interested in working together?</h5>
                    <p>Send me an email or contact me through any of my social medias listed above.</p>
                    <form action="#" id="subscribe-form">
                        {/* <input type="email" placeholder="Enter your email address" required="" id="subscribe-email" /> */}
                        {/* <button className="tf-button-st2 btn-effect" type="submit" id="subscribe-button"> <span className="effect">Subscribe</span></button> */}
                    </form>
                </div>
            </div>
            <div className="footer-bottom">
                <div className="container">
                    <div className="wrap-fx">
                        <div className="Copyright">
                            <p>HaiderJavaid 2022- ALL rights reserved</p>
                        </div>
                        {/* <ul className="list">
                            <li>
                                <Link to="#">Privacy Policy</Link>
                            </li>
                            <li>
                                <Link to="#">Cookies</Link>
                            </li>
                            <li>
                                <Link to="#">Terms & Conditions</Link>
                            </li>
                            <li>
                                <Link to="/contact">Contact Us</Link>
                            </li>
                        </ul> */}
                    </div>
                </div>
                
            </div>

            {
                isVisible && 
                <Link onClick={scrollToTop}  to='#' id="scroll-top"></Link>
            }
        </footer>
    );
}

export default Footer;