import React from 'react';
import PageTitle from '../components/pagetitle';
import { Link } from 'react-router-dom';
import Project from '../features/project/nftdetails';
import dataProject from '../assets/fake-data/dataProject';
import {AiFillGithub} from 'react-icons/ai'

import img from '../assets/images/post/cryptopiaApp.png'

function NftItemDetails(props) {
    return (
        <div className='page-item-details'>
            <PageTitle title='Project Details' />

            <section className="tf-section tf-item-details pb-mobie">
                <div className="container">
                    <div className="row">
                        <div className="col-xl-6 col-lg-6 col-md-12">
                            <div className="image-details" data-aos="fade-right" data-aos-duration="800">
                                <img src={img} alt="" />
                            </div>
                        </div>
                        <div className="col-xl-6 col-lg-6 col-md-12">
                            <div className="item-details" data-aos="fade-left" data-aos-duration="800">
                                <h5>Cryptopia</h5>
                                <p className="sub">Live Crypto currency Tracker</p>
                                <div className="action">
                                    
                                    
                                </div>
                                <p className="desc">Cryptopia is a simple web app that helps you search and track your favorite coins. I use a public API to gather all the datas and display it on the web app as well using basic CSS for the styling.</p>
                                <a href="https://cryptopiacoins.netlify.app/" target={'_blank'} className="tf-button btn-effect">
                                    <span className="boder-fade"></span>          
                                    <span className="effect">View Live Website</span>
                                </a>  
                                <a href="https://github.com/HaiderJavaid/cryptopia" target={'_blank'} className="tf-button btn-effect">
                                    <span className="boder-fade"></span>          
                                    <span className="effect">Github Code <AiFillGithub/></span>
                                </a>
                                <div className="list-product">
                                    <div className="box corner-box">
                                        <p>ReactJS</p>
                                    </div>
                                    <div className="box corner-box">
                                        <p>Web API</p>
                                    </div>
                                    <div className="box corner-box">
                                        <p>CSS</p>
                                    </div>
                                    
                                </div>         
                            </div>
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
}

export default NftItemDetails;