import React, { useState } from 'react';
import PropTypes from 'prop-types';
import './styles.scss'
import { Scrollbar, A11y , Navigation  } from 'swiper';
import { Swiper, SwiperSlide } from 'swiper/react';
import 'swiper/scss';
import 'swiper/scss/navigation';
import 'swiper/scss/pagination';
import TeamItem from './team-item';

Team.propTypes = {
    data: PropTypes.array,
};

function Team(props) {

    const {data} = props;

    const [dataBlock] = useState({
        subtitle: '01',
        title: 'About me',
        text: 'Hello! My name is Haider Javaid and I enjoy programming things that are on the internet. I am a self-taught developer adept at creating successful websites that meet peoples needs. I also have a high problem solving skills as well as dedication to learn new technologies.', 
        text2: 'Here are some of the technologies I have been working with recently:',
        tech: ['HTML & CSS, ', 'Javascript, ', 'React JS, ', 'WordPress, ', 'PHP, ', 'and Chakra UI']
    })
    return (
        <section className="tf-section tf-team">
            <div className="container">
                <div className="row">
                    <div className="col-xl-7 col-lg-5 col-md-6 col-12">
                        <div className="tf-title st2 mb-61" data-aos="fade-up" data-aos-duration="800">
                            <p className="h8 sub-title">{dataBlock.subtitle}</p>
                            <h4 className="title">{dataBlock.title}</h4>
                        </div>
                        <div className="content mobie-30" data-aos="fade-up" data-aos-duration="800">
                            
                            <p>{dataBlock.text}</p>
                            <p>{dataBlock.text2}</p>
                            {/* <ul>
                            <li>
                                {dataBlock.tech}
                            </li>
                            </ul> */}
                            <div id='box-list' className="list-product1">
                                    <div className="box corner-box">
                                    React JS
                                    </div>
                                    <div className="box corner-box">
                                            Javascript
                                    </div>
                                    <div className="box corner-box">
                                            HTML CSS
                                    </div>
                                </div>    
                                <div id='box-list' className="list-product1">
                                    <div className="box corner-box">
                                    Wordpress
                                    </div>
                                    <div id='php' className="box corner-box">
                                            PHP
                                    </div>
                                    <div className="box corner-box">
                                            Chakra UI
                                    </div>
                                </div>       
                        </div>
                    </div>
                    <div  className="col-xl-1 col-lg-1 col-md-1 col-sm-1 col-12"> 
                        <div className="wrap-team" data-aos="fade-up" data-aos-duration="800">
                            
                                {
                                    data.map(item => (
                                        <SwiperSlide key={item.id}>
                                            <TeamItem item={item} />
                                        </SwiperSlide>
                                        
                                    ))
                                }
                           
                        </div>                   
                    </div>
                </div>
            </div>
        </section>
    );
}

export default Team;