import React , {useState} from 'react';
import PropTypes from 'prop-types';
import { Link } from 'react-router-dom';
import ModalVideo from 'react-modal-video';
import 'react-modal-video/scss/modal-video.scss' ;
// import { Modal } from "react-bootstrap";
import './styles.scss'
import resume from '../../../assets/resume.pdf'

// import {Spline} from 'react-spline'

SliderItem.propTypes = {
    item : PropTypes.object,
};

function SliderItem(props) {
    const {item} = props;

    const [isOpen, setOpen] = useState(false)

    // const [modalShow, setModalShow] = useState(false);

    return (
        <div className={`box-slider`}>
           
            <div className="box-slider__main">
                <div className="container">
                    <div className="row">
                        <div className="col-xl-12 col-md-12">
                            <div className="content-box">
                            <p id="one" className="sub-title">Hello, my name is</p>
                                <h1 className="title">Haider Javaid. <span><br/>I develop web apps.</span></h1>
                                
                                <p id="two" className="sub-title">I'm a Front End Developer, experienced mainly in web based applications.<br/> This is a portfolio to showcase of my Skills and Projects.</p>
                                <div className="wrap-btn">
                                    <Link to={''} onClick={props.scrollTo} className="tf-button-st2 btn-effect"><span className="effect">All Projects</span></Link>
                                    
                                    
                                        <span className="boder-fade"></span>                                     
                                        <span className="effect">Resume/CV</span>
                                    
                                    
                                </div>
                            </div>
                        </div>
                        
                    </div>
                </div>
            </div>

            <ModalVideo channel='youtube' autoplay isOpen={isOpen} videoId="i7EMACWuErA" onClose={() => setOpen(false)} />

        </div>
    );
}

export default SliderItem;